@page "/catalog"
@using sv_ef49385ef072453d8de4d824f1dc5abe.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-link" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="_categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
        </div>
        <div class="col-md-9">
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products...</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                StartItem="_startItem"
                                EndItem="_endItem"
                                TotalCount="_totalCount"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    private List<Product> _products = new();
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private int _totalCount;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => (int)Math.Ceiling((double)_totalCount / PageSize);
    private int _startItem => _totalCount == 0 ? 0 : (_currentPage - 1) * PageSize + 1;
    private int _endItem => Math.Min(_currentPage * PageSize, _totalCount);

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            var result = await searchTask;
            _products = result.Items;
            _totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string? sortBy)
    {
        _sortBy = sortBy ?? "price_asc";
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }
}

